1	export interface Transaction {
2	  id: string;
3	  userId: string;
4	  amount: number;
5	  category: string;
6	  date: string;
7	  description: string;
8	}
9	
10	export interface CategoryGroup {
11	  category: string;
12	  transactions: Transaction[];
13	  total: number;
14	}
15	
16	export interface DuplicateGroup {
17	  key: string;
18	  transactions: Transaction[];
19	}
20	
21	export interface RunningBalanceEntry {
22	  transactionId: string;
23	  amount: number;
24	  balance: number;
25	  date: string;
26	}
27	
28	export interface SpenderSummary {
29	  userId: string;
30	  totalSpent: number;
31	  transactionCount: number;
32	}
33	
34	export interface PipelineResult {
35	  categoryGroups: CategoryGroup[];
36	  duplicates: DuplicateGroup[];
37	  topSpenders: SpenderSummary[];
