### **Function 2: findDuplicates (Lines 49-93)**
```
export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  const duplicateGroups: DuplicateGroup[] = [];
  for (let i = 0; i < transactions.length; i++) {
    for (let j = i + 1; j < transactions.length; j++) {
      const a = transactions[i];
      const b = transactions[j];
      if (
        a.userId === b.userId &&
        a.amount === b.amount &&
        a.date === b.date
      ) {
        const key = `${a.userId}|${a.amount}|${a.date}`;
        let found = false;
        for (const group of duplicateGroups) {
          if (group.key === key) {
            let aExists = false;
            let bExists = false;
            for (const t of group.transactions) {
              if (t.id === a.id) aExists = true;
              if (t.id === b.id) bExists = true;
            }
            if (!aExists) group.transactions.push(a);
            if (!bExists) group.transactions.push(b);
            found = true;
            break;
          }
        }
        if (!found) {
          duplicateGroups.push({
            key,
            transactions: [a, b],
          });
        }
      }
    }
  }
  return duplicateGroups;
}
```

**Performance Bottlenecks:**
- **Lines 53-54**: Nested loops comparing every pair - O(n²)
- **Lines 67-79**: Linear scan of duplicateGroups to find existing group
- **Lines 71-74**: Linear scan of group.transactions to check if transaction exists
- **Overall Complexity**: O(n²) comparison + O(m²) deduplication where m is number of duplicates

