import {
  Transaction,
  CategoryGroup,
  DuplicateGroup,
  RunningBalanceEntry,
  SpenderSummary,
  PipelineResult,
} from "./types.js";

/**
 * Groups transactions by category and calculates totals.
 *
 * Optimized: Uses a Map for O(1) category lookups and incrementally updates totals.
 */
export function groupByCategory(transactions: Transaction[]): CategoryGroup[] {
  const groupMap = new Map<string, CategoryGroup>();

  for (const transaction of transactions) {
    let group = groupMap.get(transaction.category);
    if (group) {
      group.transactions.push(transaction);
      group.total += transaction.amount;
    } else {
      group = {
        category: transaction.category,
        transactions: [transaction],
        total: transaction.amount,
      };
      groupMap.set(transaction.category, group);
    }
  }

  return Array.from(groupMap.values());
}

/**
 * Finds duplicate transactions (same userId + amount + date).
 *
 * Optimized: Single pass using a Map to group by composite key, then filter for duplicates.
 */
export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  const map = new Map<string, Transaction[]>();

  for (const transaction of transactions) {
    const key = `${transaction.userId}|${transaction.amount}|${transaction.date}`;
    let group = map.get(key);
    if (group) {
      group.push(transaction);
    } else {
      map.set(key, [transaction]);
    }
  }

  const duplicateGroups: DuplicateGroup[] = [];
  for (const [key, transactions] of map) {
    if (transactions.length > 1) {
      duplicateGroups.push({ key, transactions });
    }
  }

  return duplicateGroups;
}

/**
 * Calculates running balance for a specific user, sorted by date.
 *
 * Optimized: Single filter pass, single sort, single cumulative balance pass.
 */
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  // Single pass to filter user transactions
  const userTransactions: Transaction[] = [];
  for (const t of transactions) {
    if (t.userId === userId) {
      userTransactions.push(t);
    }
  }

  if (userTransactions.length === 0) {
    return [];
  }

  // Sort once
  userTransactions.sort((a, b) => a.date.localeCompare(b.date));

  // Single pass to compute running balance
  const entries: RunningBalanceEntry[] = [];
  let balance = 0;
  for (const t of userTransactions) {
    balance += t.amount;
    entries.push({
      transactionId: t.id,
      amount: t.amount,
      balance: Math.round(balance * 100) / 100,
      date: t.date,
    });
  }

  return entries;
}

/**
 * Returns the top N spenders.
 *
 * Optimized: Single pass Map accumulation, native Array.sort instead of bubble sort.
 */
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  const userMap = new Map<string, { total: number; count: number }>();

  // Single pass to accumulate totals
  for (const t of transactions) {
    let entry = userMap.get(t.userId);
    if (entry) {
      entry.total += t.amount;
      entry.count++;
    } else {
      userMap.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  // Build summaries
  const summaries: SpenderSummary[] = [];
  for (const [userId, { total, count }] of userMap) {
    summaries.push({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    });
  }

  // Native sort (O(n log n) instead of bubble sort O(n^2))
  summaries.sort((a, b) => b.totalSpent - a.totalSpent);

  return summaries.slice(0, n);
}

/**
 * Searches transactions by description text.
 *
 * Optimized: Create RegExp once, use Set for O(1) dedup.
 */
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  const pattern = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "i");
  const results: Transaction[] = [];
  const seen = new Set<string>();

  for (const transaction of transactions) {
    if (pattern.test(transaction.description)) {
      if (!seen.has(transaction.id)) {
        seen.add(transaction.id);
        results.push(transaction);
      }
    }
  }

  return results;
}

/**
 * Runs the full processing pipeline.
 */
export function processAll(
  transactions: Transaction[],
  topN: number = 10
): PipelineResult {
  const categoryGroups = groupByCategory(transactions);
  const duplicates = findDuplicates(transactions);
  const topSpendersList = topSpenders(transactions, topN);

  return {
    categoryGroups,
    duplicates,
    topSpenders: topSpendersList,
  };
}

